// Parse dollar amount: "$ 7,200.00" → 7200, "$ (7,162.00)" → -7162, "$ -" → 0
function parseAmount(s) {
  if (!s) return 0;
  s = s.toString().replace(/\$/g,'').replace(/,/g,'').trim();
  if (s.startsWith('(') && s.endsWith(')')) return -parseFloat(s.slice(1,-1)) || 0;
  if (s === '-' || s === '' || s === '-   ') return 0;
  return parseFloat(s) || 0;
}

// Extract car key from car ID string
function extractCarKey(s) {
  if (!s) return null;
  const m = s.match(/Car\d+/i);
  return m ? m[0].toUpperCase().replace('CAR','Car') : null;
}

function parseDate(s) {
  if (!s) return null;
  try { return new Date(s); } catch(e) { return null; }
}

