async function importTransactions() {
  const mongoUrl = process.env.MONGO_URL || 'mongodb://localhost:27017/deccan_rental';
  const client = new MongoClient(mongoUrl, mongoUrl.startsWith('mongodb+srv://') ? { tls: true } : {});
  await client.connect();
  const dbName = process.env.DB_NAME || 'deccan_rental';
  const db = client.db(dbName);
  const cars = await db.collection('cars').find({}).toArray();

  const carMap = {};
  cars.forEach(c => { carMap[c.vehicleKey] = c; });

  await db.collection('transactions').deleteMany({});

  const transactions = raw.map(r => {
    const [carIdStr, customer, account, date, type, subType, amountStr, notes, month, year] = r;
    const carKey = extractCarKey(carIdStr);
    const car = carKey ? carMap[carKey] : null;
    const amount = parseAmount(amountStr);
    const isOverhead = carIdStr === 'Overhead';
    const isIncome = amount > 0;

    return {
      _id: uuidv4(),
      carId: car?._id || null,
      carKey: carKey || 'OVERHEAD',
      carName: car?.name || (isOverhead ? 'Overhead' : carIdStr),
      customer: customer || '',
      account: account || '',
      date: parseDate(date),
      type,
      subType: subType || '',
      amount,
      isIncome: isIncome,
      isExpense: amount < 0,
      notes: notes || '',
      month,
      year: parseInt(year) || null,
      createdAt: new Date(),
    };
  });

  await db.collection('transactions').insertMany(transactions);

  // Summary
  const income = transactions.filter(t => t.isIncome).reduce((s,t) => s+t.amount, 0);
  const expenses = transactions.filter(t => t.isExpense).reduce((s,t) => s+t.amount, 0);
  const byType = {};
  transactions.forEach(t => { byType[t.type] = (byType[t.type]||0) + 1; });

  console.log('Imported', transactions.length, 'transactions');
  console.log('Total Income:  $' + income.toFixed(2));
  console.log('Total Expense: $' + Math.abs(expenses).toFixed(2));
  console.log('Net:           $' + (income + expenses).toFixed(2));
  console.log('\nBy Type:');
  Object.entries(byType).sort((a,b) => b[1]-a[1]).forEach(([t,c]) => console.log(' ', t+':', c));

  await client.close();
}
importTransactions().catch(console.error);
